"""
MKT Christ Commentary — Deuteronomy chapters 32–34
Run: python3 scripts/zc-christ-deuteronomy-32-34-fill.py

Key christological decisions for this range:
- Ch 32 Song of Moses: 'The Rock' title (vv. 4,15,18,30,31) is Paul's explicit
  Christological identification in 1 Cor 10:4 — 'that rock was Christ'. This is treated
  as the dominant Christological thread of the entire song
- Deut 32:21 (lo'-am / 'not a people') is Paul's Romans 10:19 citation for the
  Gentile mission; 32:35 ('vengeance is mine') is Paul's Romans 12:19; 32:43 (Rejoice,
  O nations) is Romans 15:10 — three Paul citations in a single chapter
- Ch 33: Moses's final blessing as prototype for Christ's last words of blessing before
  ascension; the 'man of God' title as prophetic category Christ fulfills and surpasses
- Ch 34: The Moses-cannot-enter / Joshua-can-enter typology is the most sustained
  NT typology in Deuteronomy: Law (Moses) brings to the border, Grace (Jesus/Yeshua)
  brings across; Hebrews 3-4 makes this explicit with 'Jesus gives rest, Moses does not'
- 34:10 ('no prophet like Moses known face to face') is the limit-claim that Deut 18:15
  promised would be surpassed, and that Heb 3:3-6 and John 1:18 fulfill
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DEUT = {
  "32": {
    "1": "<p>The Song of Moses opens by summoning heaven and earth as witnesses — the covenant court convened at cosmic scale. Moses's call 'listen, O heavens ... let the earth hear' echoes the covenant lawsuit opening of Isaiah 1:2 ('hear, O heavens! Listen, O earth! For the LORD has spoken') and Micah 1:2 ('hear, O peoples ... listen, O earth and all who live in it'). In Revelation 12, the heavens are still the witness-court for the great conflict; in the Sermon on the Mount, Jesus promises that 'until heaven and earth disappear, not the smallest letter or stroke of a pen will by any means disappear from the Law' (Matt 5:18) — maintaining the creation-witness theology.</p>",
    "2": "<p>'Let my teaching fall like rain and my speech settle like dew, like gentle showers on new grass' — the word-as-rain metaphor anticipates Isaiah 55:10-11: 'as the rain and the snow come down from heaven ... so is my word that goes out from my mouth: it will not return to me empty.' Jesus's parable of the sower (Matt 13:3-9, 18-23) operates on the same agricultural-word logic: the word is seed that falls on different soils, producing nothing or abundant harvest depending on the receiver's condition. The dew metaphor for gentle, life-giving divine speech is also used of the Messiah's influence (Ps 72:6: 'he will be like rain falling on a mown field, like showers watering the earth').</p>",
    "3": "<p>'I will proclaim the name of the LORD; give glory to our God!' — the proclamation of the divine name is the song's doxological purpose. Jesus's high priestly prayer returns to this: 'I have made your name known to those you gave me' (John 17:6, 26). The writer of Hebrews applies Psalm 22:22 ('I will declare your name to my brothers and sisters') to Christ: 'he is not ashamed to call them brothers and sisters, saying, I will declare your name to my brothers' (Heb 2:12). The proclamation of the divine name reaches its NT summit in Jesus's revelation of the Father — the name proclaimed from Deuteronomy to the Gospels is ultimately the name of the Triune God.</p>",
    "4": "<p>'The Rock — his work is flawless, and all his ways are just. A faithful God, without fault — he is righteous and upright' — the title 'The Rock' (<em>haṣṣûr</em>) recurs throughout the song (vv. 15, 18, 30, 31) and becomes Paul's explicit Christological identification: 'they drank from the spiritual rock that accompanied them, and that rock was Christ' (1 Cor 10:4). The attributes here — flawless, just, faithful, faultless, righteous, upright — are the character qualifications of the perfect covenant mediator, which is why Paul can apply the Rock title to Christ: he is the one in whom all of God's faithfulness and justice are embodied and enacted.</p>",
    "5": "<p>'They have corrupted themselves — they are a perverse and crooked generation' — Jesus quotes this precise phrase in Matthew 17:17: 'you unbelieving and perverse generation' (addressing the disciples who failed to cast out the demon). In Philippians 2:15 Paul uses it positively: 'so that you may become blameless and pure, children of God without fault in a warped and crooked generation' — where the church is the contrast to, not the embodiment of, the Deuteronomy diagnosis. The phrase is thus both a warning (Jesus's rebuke) and a vocation (Paul's exhortation): believers are called to be the un-corrupt generation within the corrupt one.</p>",
    "6": "<p>'Is he not your father who made you — who formed you and gave you your strength?' — the father-creator question presents YHWH's paternity in creative terms. Jesus's revolution is to make this implicit Deuteronomy theology explicit and personal: 'Our Father in heaven' (Matt 6:9) is not a new theological category but the fulfillment of what the Song of Moses implied. John 1:12-13 extends it further: those who receive Christ are given 'the right to become children of God — children born not of natural descent, nor of human decision or a husband's will, but born of God.' The formation language here anticipates Paul's new creation: 'if anyone is in Christ, the new creation has come' (2 Cor 5:17).</p>",
    "7": "<p>'Remember the ancient days; think back across many generations. Ask your father — he will tell you; ask the elders — they will explain' — the intergenerational memory-transmission of YHWH's acts is the Deuteronomic covenant pedagogy. Jesus regularly invokes this pattern: 'you have heard that it was said to the people long ago' (Matt 5:21-48), positioning his teaching in relation to the received tradition. Paul similarly instructs: 'I received from the Lord what I also passed on to you' (1 Cor 11:23) — the apostolic chain of transmission that carries the Christ-event into subsequent generations, exactly as Moses commanded the chain of testimony in the wilderness.</p>",
    "8": "<p>'When the Most High apportioned the nations their inheritance and divided the human race, he fixed the boundaries of every people according to the number of the sons of God' — the divine governance of the nations at creation. Paul cites this in the Areopagus address: 'he made all the nations from one man ... he fixed the appointed times and the boundaries of their lands' (Acts 17:26), adding the redemptive purpose: 'so that they would seek him and reach out for him' (v. 27). The nations' division at creation is the precondition for their gathering in Christ: what YHWH divided for their protection, Christ reunites as 'one new humanity' (Eph 2:15).</p>",
    "9": "<p>'But the LORD's own portion is his people; Jacob is what he has claimed as his inheritance' — while the nations received their allotted deities (or guardians), YHWH himself took Israel as his personal inheritance. Paul applies this election language to the church: 'in him we were also chosen, having been predestined according to the plan of him who works out everything in conformity with the purpose of his will' (Eph 1:11); 'the riches of his glorious inheritance in his holy people' (Eph 1:18). Peter identifies the church as 'a chosen people ... God's special possession' (1 Pet 2:9) — the language of divine-inheritance election carried from Deuteronomy into the new covenant community.</p>",
    "10": "<p>'He found his people in a barren wasteland, in the howling desert. He surrounded them, looked after them, guarded them like the apple of his eye' — the wilderness-finding is divine election described as rescue from desolation. 'Apple of his eye' (<em>ʾîšôn ʿênô</em>, the pupil of his eye) is the most intimate protection image in the OT (Ps 17:8: 'keep me as the apple of your eye; hide me in the shadow of your wings'). Jesus invokes the same protective image with maternal rather than ocular imagery: 'how often I have longed to gather your children together, as a hen gathers her chicks under her wings' (Matt 23:37; Luke 13:34) — the divine protectiveness expressed in embodied, incarnational terms.</p>",
    "11": "<p>'Like an eagle that rouses its young from the nest, hovers over them, spreads its wings to catch them, and carries them on its feathers' — the eagle-parent image for divine care. The eagle's hovering over its young connects to the Spirit hovering over the waters at creation (Gen 1:2), suggesting that the divine care for Israel recapitulates the creative care for the cosmos. At Jesus's baptism, the Spirit 'descended on him like a dove' (Matt 3:16) — the hovering Spirit of creation and the Exodus care now present in embodied form at the inauguration of the new creation. The eagle who carries on its feathers is the grace that precedes and undergirds the disciple's own movement.</p>",
    "12": "<p>'The LORD alone was his guide — no foreign god was with him' — the exclusive divine guidance through the wilderness, without any foreign divine mediator. Jesus's self-identification as 'the way, and the truth, and the life' (John 14:6) — 'no one comes to the Father except through me' — is the NT's exclusive-guidance claim: as YHWH alone guided Israel through the wilderness, so the Son alone is the way through the greater wilderness of this age. The exclusivity is not arbitrary but ontological: the Guide is the only one capable of the journey.</p>",
    "13": "<p>'He set him on the heights of the land and fed him with the produce of the fields. He gave him honey from the rock and oil from the flinty crag' — the Rock yields honey (contrast v. 37-38 where the gods of the enemy yield nothing). The Rock that flows with honey is the source of unexpected sweetness from an impossible location — the same theological logic as 1 Corinthians 10:4's identification of the rock as Christ. The honey from the rock anticipates the Word of God being 'sweeter than honey' (Ps 19:10; 119:103) — the Rock Christ who is also the Word, from whom flows the sweetness of divine revelation.</p>",
    "14": "<p>'The fat of choice lambs and Bashan rams and goats, the finest wheat — and you drank the blood of the grape' — the covenant feast from YHWH's provision. The eucharistic echo is unmistakable: 'the finest wheat' (<em>ḥeleb ḥiṭṭāh</em>) and 'the blood of the grape' are the bread and wine of the Lord's Supper's OT antecedents. Paul's eucharistic theology in 1 Corinthians 10-11 draws explicitly on the wilderness provision (v. 3: 'they ate the same spiritual food and drank the same spiritual drink') — the wilderness feast under Moses is a type of the eucharistic feast under Christ. The covenant meal of Deuteronomy 32 finds its fulfillment at the Lord's table.</p>",
    "15": "<p>'But Jeshurun became fat and rebellious — you grew fat, sleek, and bloated. Then Israel abandoned the God who made them and mocked the Rock their Savior' — the prosperity-apostasy pattern: abundance leads to forgetfulness. Jesus's parable of the sower identifies 'the deceitfulness of wealth and the desires for other things' as the thorns that choke the word (Mark 4:19). More directly, the 'mocking of the Rock their Savior' (<em>nabal ṣûr yĕšûʿātô</em>) is theologically dense: <em>ṣûr yĕšûʿāh</em> (Rock of his salvation) uses the root of the name Jesus (<em>yēšûaʿ</em>) — the Rock who is salvation was mocked by those he sustained. The passion narrative's mockery of Jesus is the culmination of this pattern.</p>",
    "16": "<p>'They made him jealous with foreign gods; with detestable practices they provoked his anger' — the divine jealousy (<em>qinʾāh</em>) is the passionate covenant-loyalty response to betrayal. Paul's concern that the Corinthians might cause Christ to be jealous uses this same category: 'are we trying to arouse the Lord's jealousy? Are we stronger than he?' (1 Cor 10:22). James 4:5 cites a scripture that 'the spirit he caused to dwell in us envies intensely' — the covenantal jealousy of a committed God toward the beloved. The detestable practices that provoke divine jealousy in Deuteronomy are the idolatrous compromises Paul warns against at the Lord's table.</p>",
    "17": "<p>'They offered sacrifices to demons — not to God — to gods they had never known, to newly arrived gods your ancestors did not fear' — Paul quotes this directly in 1 Corinthians 10:20-21: 'the sacrifices of pagans are offered to demons, not to God, and I do not want you to be participants with demons. You cannot drink the cup of the Lord and the cup of demons too; you cannot have a part in both the Lord's table and the table of demons.' The Deuteronomy warning against demon-sacrifice becomes Paul's argument for eucharistic exclusivity: the Lord's Supper is the covenant meal that precludes simultaneous participation in any demonic communion.</p>",
    "18": "<p>'You neglected the Rock who fathered you; you forgot the God who gave you life' — the second Rock occurrence in the song, this time with the father-and-life-giver attributes. The verb 'neglected' (<em>tĕšî</em>, from <em>šāyāh</em>, to be unmindful of) combined with 'forgot' (<em>tiškāḥ</em>) describes not active rebellion but passive forgetfulness — the erosion of covenant memory. Jesus's parable of the prodigal son (Luke 15:11-32) is the narrative form of this diagnosis: the son who forgot his father and wasted the inheritance. The father running to meet the returning son is YHWH responding to the penitent return that the Song of Moses calls for.</p>",
    "19": "<p>'When the LORD saw this he was filled with contempt for them, provoked by his sons and daughters' — the divine rejection is expressed in parental terms: the offspring who have repudiated their father. The prodigal's self-understanding on returning ('I am no longer worthy to be called your son; make me one of your hired servants,' Luke 15:19) is precisely the condition of verses 19-20. Hebrews 12:5-11 reframes divine correction as fatherly discipline (<em>paideia</em>): 'the Lord disciplines the one he loves' — what the Song of Moses calls YHWH's provoked contempt, Hebrews reinterprets as painful-but-loving formation.</p>",
    "20": "<p>'I will hide my face from them and wait to see what becomes of them — they are a crooked generation, children with no loyalty' — the divine face-hiding (<em>hastarat pānîm</em>) is the covenant-curse counterpart to the Aaronic blessing ('the LORD make his face shine on you,' Num 6:25). Jesus quotes Psalm 22:1 from the cross ('My God, my God, why have you forsaken me?') — the ultimate face-hiding, experienced by the sinless Son in the place of sinful Israel. Isaiah 53:3 applies the face-hiding specifically to the Suffering Servant: 'he was despised ... like one from whom people hide their faces.' The forsakenness of the cross is the concentrated endurance of what Israel's infidelity deserved.</p>",
    "21": "<p>'They provoked my jealousy with something that is not God; they angered me with worthless idols. So I will provoke their jealousy with those who are not a people (<em>lōʾ-ʿam</em>); I will make them angry with a foolish nation' — Paul quotes this verse in Romans 10:19 as prophecy of the Gentile mission: 'Did Israel not understand? First Moses says, I will make you envious by those who are not a nation; I will make you angry by a nation that has no understanding.' The Gentile inclusion is not a plan-B deviation from Israel-focused redemption but a covenantal strategy announced in the Song of Moses — YHWH will use the unexpected salvation of the Gentiles to provoke Israel's return.</p>",
    "22": "<p>'A fire is ignited by my anger that burns down to the depths of the realm of the dead, consuming the earth and its harvest, and setting the foundations of the mountains ablaze' — the cosmic scope of divine judgment. The same imagery appears in Revelation 20:14 (Death and Hades thrown into the lake of fire) and in Peter's eschatological vision: 'the present heavens and earth are reserved for fire, kept for the day of judgment and destruction of the ungodly' (2 Pet 3:7). Jesus uses fire-imagery for judgment throughout the Gospels (Matt 13:40-42; 25:41), placing himself as the one who comes to cast fire on the earth (Luke 12:49).</p>",
    "23": "<p>'I will pile disaster upon them and exhaust my arrows against them' — the divine arrows of judgment (Ps 7:12-13; Lam 3:12-13). The same arrows that represent YHWH's judgment also become the fiery arrows of Ephesians 6:16 that the 'shield of faith' extinguishes — now wielded by the enemy against believers, but quenched by the defensive armor Christ provides. Christ bore the arrows of divine judgment (cf. Isa 53:5: 'by his wounds we are healed') so that those who trust in him receive the shield rather than the quiver.</p>",
    "24": "<p>'Ravaged by famine, consumed by burning fever and bitter pestilence — I will set wild beasts on them' — the covenant-curse inventory matches the four horsemen of Revelation 6 (famine, pestilence, death, wild beasts). The Revelation horse-riders are the unleashing of what Deuteronomy 28-32 threatened: the covenant sanctions of a broken treaty. Jesus's Olivet Discourse (Matt 24:7: 'famines and earthquakes in various places') anticipates the same covenant-judgment pattern in the generation before 70 CE. The seal-judgments of Revelation represent the Deuteronomic curse-sequence reaching its eschatological culmination.</p>",
    "25": "<p>'The sword will cut them down outside; inside the city, terror — for young and old alike, the nursing infant and the elderly' — the indiscriminate sweep of judgment across all demographics. Jesus wept over Jerusalem foreseeing exactly this: 'your enemies will ... dash you to the ground, you and the children within your walls. They will not leave one stone on another, because you did not recognize the time of God's coming to you' (Luke 19:41-44). Luke 21:22-24 describes the 66-70 CE fulfillment in Deuteronomic terms: 'these are the days of vengeance as a fulfillment of all that has been written.' What Moses sang in the wilderness Jesus mourned over Jerusalem.</p>",
    "26": "<p>'I said to myself, I will scatter them to the four winds; I will erase their memory from the face of the earth' — the divine inclination to annihilate, restrained in v. 27. The divine decision to not destroy despite just cause mirrors the intercession theme throughout the Pentateuch (Moses's intercessions in Exod 32 and Num 14). The restraint of judgment for the sake of divine reputation is ultimately fulfilled in Christ: 'God did not send his Son into the world to condemn the world, but to save the world through him' (John 3:17) — the judgment that was deserved was restrained and then redirected to the Son, not because Israel earned reprieve but because YHWH's purposes demanded a greater outcome.</p>",
    "27": "<p>'Had I not feared the taunting of the enemy — that their foes would misread it and claim, Our own power did this; the LORD had no part in it' — the divine concern for misattribution of glory. Paul's entire theology of weakness-through-which-God-displays-power addresses the same misattribution problem: 'God chose the foolish things of the world to shame the wise ... so that no one may boast before him' (1 Cor 1:27-29). The cross, an apparent defeat, is precisely the kind of divine action that prevents human boasting: 'the message of the cross is foolishness to those who are perishing, but to us who are being saved it is the power of God' (1 Cor 1:18).</p>",
    "28": "<p>'This enemy nation is without sense; there is no understanding in them' — the nations that execute YHWH's judgment without understanding the covenantal context they serve. Paul applies the same analysis to humanity without the Spirit: 'the person without the Spirit does not accept the things that come from the Spirit of God but considers them foolishness, and cannot understand them' (1 Cor 2:14). The enemy's failure of understanding is not evidence of its innocence but of its limited perspective; it serves divine purposes without comprehending them, just as those who crucified Christ 'would not have crucified the Lord of glory' had they understood (1 Cor 2:8).</p>",
    "29": "<p>'If they had any wisdom, they would grasp this; they would understand what lies ahead' — the appeal to future-oriented wisdom: if you understood where your course is leading, you would change direction. Jesus makes the same appeal in his laments over Jerusalem (Luke 19:42: 'if you, even you, had only known on this day what would bring you peace') and in the eschatological warnings of the Olivet Discourse. Proverbs 14:12 captures the principle: 'there is a way that appears to be right, but in the end it leads to death.' The prophetic function of understanding the future telos is what both Moses and Jesus offer their hearers.</p>",
    "30": "<p>'How else could one man rout a thousand, or two men put ten thousand to flight, unless their Rock had surrendered them and the LORD had given them up?' — the military prowess is the Rock's gift, and its withdrawal is the Rock's judgment. The same logic appears in Romans 1:24,26,28: YHWH 'handed them over' to the consequences of their choices — the surrender is the judgment. Christ's abandonment on the cross ('my God, my God, why have you forsaken me?') is the Rock being surrendered by the Father as the covenant-bearing Son takes the place of the covenant-breaking people.</p>",
    "31": "<p>'Their rock is nothing like our Rock — even our enemies can see that' — the comparative religious claim: the enemy nations have their own protective deities, but none compares to Israel's Rock. Paul's cosmological christology makes the same comparative claim in the strongest possible terms: 'for us there is but one God, the Father, from whom all things came and for whom we live; and there is but one Lord, Jesus Christ, through whom all things came and through whom we live' (1 Cor 8:6). The uniqueness of the Rock is not merely a religious preference but an ontological reality: the Creator-sustainer stands in a different category from all other claimed deities.</p>",
    "32": "<p>'Their vine springs from the vine of Sodom, from the fields of Gomorrah — their grapes are poisonous, their clusters filled with bitterness' — the vine/fruit imagery for moral character. Jesus uses the same agricultural metaphor: 'every good tree bears good fruit, but a bad tree bears bad fruit' (Matt 7:17); 'I am the vine; you are the branches' (John 15:5). The vine of Sodom that produces poisonous grapes is the vine unconnected to the life-giving source; disconnection from the true vine (Christ) produces the same toxic fruit that the enemy's vine produces. John 15:6: 'if you do not remain in me, you are like a branch that is thrown away and withers; such branches are picked up, thrown into the fire and burned.'</p>",
    "33": "<p>'Their wine is snake venom — the deadly poison of cobras' — the venom-wine as the antitype of the covenant cup. Psalm 75:8 uses the cup of divine wrath in exactly this register: 'in the LORD's hand is a cup full of foaming wine mixed with spices; he pours it out, and all the wicked of the earth drink it down to its very dregs.' Jesus asked, in Gethsemane, 'my Father, if it is possible, may this cup be taken from me' (Matt 26:39) — the cup of divine wrath being drained by the Righteous One so that his people would receive the cup of blessing instead (1 Cor 10:16).</p>",
    "34": "<p>'Is not this stored up by me — sealed in my storehouses?' — the divine sovereignty over judgment: the catastrophe is not random or unexpected but is stored, prepared, and released according to divine timing. The same sovereign timing appears in Revelation's bowls and seals — the wrath is precisely measured and precisely timed. Peter's answer to the question of why judgment has not yet fallen uses the same sovereignty-of-timing argument: 'the Lord is not slow in keeping his promise ... he is patient with you, not wanting anyone to perish, but everyone to come to repentance' (2 Pet 3:9). The sealed storehouses contain judgment that is certain but patient.</p>",
    "35": "<p>'Vengeance belongs to me — I will repay. In due time their foot will slip; their day of disaster is coming, and doom approaches fast' — Paul quotes this exactly in Romans 12:19: 'do not take revenge, my dear friends, but leave room for God's wrath, for it is written: It is mine to avenge; I will repay, says the Lord.' Hebrews 10:30 also quotes it: 'for we know him who said, It is mine to avenge; I will repay.' The divine reservation of vengeance is the theological foundation of non-retaliation ethics: because YHWH guarantees justice, believers are freed from the compulsion to enforce it themselves. Christ's suffering-without-retaliation embodies this: 'he entrusted himself to him who judges justly' (1 Pet 2:23).</p>",
    "36": "<p>'The LORD will vindicate his people and have compassion on his servants when he sees their strength is spent and none remain' — Hebrews 10:30 cites the vindication clause alongside v. 35's vengeance clause, framing the two as the twin acts of the righteous Judge. The vindication of the suffering servant at the moment of complete helplessness is the resurrection pattern: Christ was crucified in weakness, yet lives by God's power' (2 Cor 13:4). The timing — compassion when strength is spent — is the pattern of the Cross: YHWH vindicates when the servant has poured himself out completely.</p>",
    "37": "<p>'Then he will say, Where are their gods — the rock they depended on for safety?' — the rhetorical taunt over defeated false gods. The triumphal Christ is described in Colossians 2:15 as having 'disarmed the powers and authorities, making a public spectacle of them, triumphing over them by the cross' — the eschatological equivalent of YHWH's taunt over the nations' failed deities. The cross, which appeared to be defeat, is the site of the cosmic defeat of the enemy: the 'gods' that once threatened have been made a public spectacle.</p>",
    "38": "<p>'The gods who ate the fat of their sacrifices and drank the wine of their offerings — let them rise up now and rescue you! Let them be your refuge!' — the invitation to the failed gods proves their impotence. Elijah's taunt on Carmel follows the same logic (1 Kings 18:27: 'Shout louder! Surely he is a god! Perhaps he is deep in thought, or busy, or traveling. Maybe he is sleeping and must be awakened'). Christ's resurrection is the supreme demonstration of the contrast: when the disciples called 'Lord, save us!' (Matt 8:25) and 'Lord, if you had been here, my brother would not have died' (John 11:21), the living Rock responded — unlike the gods who ate the fat but could not rise.</p>",
    "39": "<p>'See now that I alone am God — there is no other god beside me. I put to death and I bring to life; I wound and I heal; no one can deliver out of my hand' — the monotheism claim is immediately expressed in terms of sovereignty over death and life. Jesus applies the same life-and-death sovereignty to himself: 'I am the resurrection and the life' (John 11:25); 'I am the Living One; I was dead, and now look, I am alive for ever and ever! And I hold the keys of death and Hades' (Rev 1:18). The 'no one can deliver out of my hand' becomes John 10:29: 'no one can snatch them out of my Father's hand' — the same inescapable divine grip now expressed as saving protection rather than judgment.</p>",
    "40": "<p>'For I raise my hand toward heaven and declare: I live forever' — the divine self-oath using immortality as the ground of reliable promise. Hebrews 6:13-17 grounds the covenant oath's reliability in YHWH's eternity: 'since there was no one greater for him to swear by, he swore by himself, saying, I will surely bless you.' The risen Christ embodies the eternal life on which the oath rests: 'he lives forever' (Heb 7:24-25) is the ground of his permanent intercession — 'he is able to save completely those who come to God through him, because he always lives to intercede for them.'</p>",
    "41": "<p>'I will sharpen my flashing sword; my hand will grip the instrument of judgment; I will repay my enemies and punish those who hate me' — the divine warrior taking up arms for judgment. The same image appears in the Revelation vision of Christ's return: 'coming out of his mouth is a sharp sword with which to strike down the nations' (Rev 19:15). The sword from the mouth is the word of God (Heb 4:12: 'the word of God is alive and active, sharper than any double-edged sword'), meaning that Christ's judgment is enacted through his word — the instrument of salvation becomes the instrument of condemnation for those who reject it.</p>",
    "42": "<p>'My arrows will be drunk with blood as my sword devours flesh — the blood of the slain and the captives, from the heads of the enemy leadership' — the comprehensive divine judgment that leaves no leader exempt. Revelation 19:17-18 mirrors this with the vision of the great supper of God: 'come, gather together for the great supper of God, so that you may eat the flesh of kings, generals, and the mighty.' The reversal of the covenant feast (where YHWH feeds his people) into a feast of birds over the fallen enemy is the ultimate covenant-inversion — what was promised to the covenant-breakers in Deut 28:26 comes to pass in the final judgment.</p>",
    "43": "<p>'Rejoice, O heavens, with his people, and bow before him, all divine beings. For he avenges the blood of his servants; he takes vengeance on his enemies and makes atonement for his land and people' — Paul quotes the LXX version of this verse in Romans 15:10 ('Rejoice, you Gentiles, with his people') as the second of four OT proof-texts for the Gentile inclusion in salvation: 'the Gentiles may glorify God for his mercy.' The Song of Moses, the covenant lawsuit of Deuteronomy, ends with the universal summons for all nations to rejoice in YHWH's vindication — the scope that was always embedded in the covenant reaches its full expression in the Gentile mission of the Gospel.</p>",
    "44": "<p>Moses and Hoshea (Joshua) recite the song together — the outgoing mediator and his successor delivering the covenant witness in tandem. The two-witness requirement of Deuteronomy 17:6 and 19:15 is fulfilled in the joint delivery. The pattern anticipates the apostolic partnership of testimony: Jesus sent out disciples 'two by two' (Mark 6:7; Luke 10:1), and the two witnesses of Revelation 11 deliver their testimony in the same Moses-Joshua tandem pattern. Christ, who gathers his witnesses in pairs, is the one whose testimony is ultimately confirmed by two witnesses — the Father and the Spirit (John 8:18: 'I am one who testifies for myself; my other witness is the Father who sent me').</p>",
    "45": "<p>The conclusion of the song-recitation: Moses 'finished reciting all these words to all Israel.' The completeness is emphasized — every word delivered, no message withheld. Jesus's similar sense of completed proclamation: 'I have spoken openly to the world' (John 18:20); 'everything that I learned from my Father I have made known to you' (John 15:15). The faithful messenger who delivers the full message and holds nothing back is the model that Christ perfectly fulfills — the prophet who does not soften or abbreviate the covenant address.</p>",
    "46": "<p>'Take these warnings to heart — all the words I am charging you with today — and pass them on to your children so that they will follow all the words of this law carefully' — the command to transmit the covenant to the next generation is the Deuteronomic pedagogy. The Great Commission (Matt 28:20: 'teaching them to obey everything I have commanded you') is structured identically: the disciple-making mission is precisely this intergenerational transmission of the full covenant address of Christ. 'All the words' of Moses and 'everything I have commanded' of Jesus share the same comprehensiveness — the covenant addresses demand complete transmission.</p>",
    "47": "<p>'This is not a trivial thing — it is your very life. And by keeping it, you will live for many years in the land you are crossing the Jordan to possess' — the law as life itself. Jesus radicalizes this: 'very truly I tell you, whoever obeys my word will never see death' (John 8:51). The Deuteronomy equation of law-keeping and life is fulfilled christologically: the one who embodies and fulfills the law's demands on humanity's behalf (Rom 8:3-4: 'he condemned sin in the flesh, in order that the righteous requirement of the law might be fully met in us') is the life himself (John 14:6: 'I am the way and the truth and the life').</p>",
    "48": "<p>The frame-narrative resumes: YHWH's final speech to Moses is delivered on the same day as the song's completion — the last day of Moses's covenant ministry. Jesus's final words before the ascension are similarly compressed into his last appearances — the post-resurrection teaching over forty days (Acts 1:3) culminating in the Great Commission. The 'that same day' (<em>beʿeṣem hayyôm hazzeh</em>) marks a divine punctuality: the timing of Moses's call to ascend is exact, as was Jesus's 'it is accomplished' (John 19:30) at the precisely appointed hour.</p>",
    "49": "<p>'Climb to the top of the Abarim range, to Mount Nebo in Moab, across from Jericho, and look out over the land of Canaan that I am giving to Israel as their own' — the mountain vision before death. Moses sees what he cannot enter; the transfiguration (Matt 17:1-8) reverses the dynamic: Moses on a mountain with Jesus, witnessing the fulfillment of what he could only preview. The one who was denied entry into the land appears at the fulfillment of the land's purposes — standing with Elijah and the disciples beside the one who will give rest that the land only typified. Moses's exclusion from Canaan was never the end of his story.</p>",
    "50": "<p>'There on the mountain you climb, you will die and be joined to your ancestors, just as your brother Aaron died on Mount Hor and was gathered to his ancestors' — the parallel deaths of the two brothers on two mountains frames the end of the Exodus generation's leadership. Moses's death on the mountain connecting to a vision of the Promised Land is a type of Christ's death outside Jerusalem — the one who brings others to the inheritance he entered before them, not as failure but as sacrifice. Hebrews 11:39-40 applies the same logic to all the OT saints: 'they did not receive what was promised ... since God had planned something better for us so that only together with us would they be made perfect.'</p>",
    "51": "<p>'Because you were unfaithful to me in the presence of Israel at the waters of Meribah-kadesh' — the reason for Moses's exclusion: a single act of speaking-rather-than-speaking-to the rock (Num 20:8-12), which failed to represent YHWH as holy before the people. The gravity of the leader's representative responsibility is immense: Moses's failure is traced not to private sin but to public misrepresentation of divine character. The contrast with Christ is absolute: Jesus, the faithful and true witness (Rev 3:14), never misrepresented the Father — he is 'the exact representation of his being' (Heb 1:3), the mediator who embodies precisely what Moses could not.</p>",
    "52": "<p>'You will see the land ahead of you, but you will not enter it — the land I am giving to Israel' — Moses's final covenant limitation. The distinction between seeing and entering is the Law's limitation: the Mosaic covenant can reveal the destination but cannot bring the recipient across. Paul makes this the cornerstone of the Galatians argument (Gal 3:19-24): the law was a guardian leading to Christ, but 'now that this faith has come, we are no longer under a guardian' (Gal 3:25). What Moses surveyed from Nebo, Joshua/Jesus actually enters — the name change from Hoshea to Yeshua (Num 13:16; Deut 32:44) is the NT's interpretive signal that the one who brings the inheritance is the name-bearer of salvation.</p>",
  },
  "33": {
    "1": "<p>Moses is identified as 'the man of God' (<em>ʾîš hāʾĕlōhîm</em>) — the standard title for a prophet who has stood in the divine presence (used of Elijah, Elisha, and Samuel). Moses's farewell blessing over the twelve tribes is structurally parallel to Jacob's blessing of his sons (Gen 49) and to Jesus's Beatitudes as a covenant-community constitution. Hebrews 3:3-6 makes the Moses-to-Christ comparison explicit: 'Jesus has been found worthy of greater honor than Moses, just as the builder of a house has greater honor than the house itself.' The man of God delivers the final blessing; the Son of God is the blessing itself.</p>",
    "2": "<p>'The LORD came from Sinai; he rose over us from Seir; he shone forth from Mount Paran; he arrived with ten thousands of holy ones; from his right hand came a fiery law for them' — the theophany-arrival of YHWH with the angelic host. The same imagery describes Christ's return: 'when the Son of Man comes in his glory, and all the angels with him' (Matt 25:31); 'the Lord himself will come down from heaven, with a loud command, with the voice of the archangel and with the trumpet call of God' (1 Thess 4:16). The Sinai theophany is the prototype of the Parousia: YHWH arriving in glory with his holy ones, now fulfilled in Christ returning with his angelic escort and his saints (1 Thess 3:13: 'when our Lord Jesus comes with all his holy ones').</p>",
    "3": "<p>'He loves his people — all his holy ones are in his care. They bow at his feet and receive his instructions' — the pastoral image of divine love expressed through protective care and authoritative teaching. Jesus embodied both: 'when he saw the crowds, he had compassion on them, because they were harassed and helpless, like sheep without a shepherd' (Matt 9:36); and 'he taught as one who had authority' (Matt 7:29). The disciples who 'bow at his feet' are the women at the resurrection (Matt 28:9: 'they came to him, clasped his feet and worshiped him') and the disciples after the ascension (Luke 24:52: 'they worshiped him').</p>",
    "4": "<p>'Moses gave us the law — an inheritance for the assembly of Jacob' — the Torah as the inheritance that structures community identity. Paul contrasts Torah-as-inheritance with the promise-inheritance of Abraham (Gal 3:15-18): the law came 430 years after the promise and does not annul it. But the contrast leads to synthesis in Hebrews 8:6-13: Christ mediates 'a better covenant, which was established on better promises' — the law-inheritance Moses gave is superseded but not negated; the new covenant writes the same fundamental demand (love YHWH wholly, love neighbor) on the heart by the Spirit rather than on stone.</p>",
    "5": "<p>'The LORD became king over Jeshurun when the leaders of the people assembled, when all the tribes of Israel came together' — the covenantal installation of YHWH as king over his assembled people. The gathering of all the tribes for covenant assembly anticipates the eschatological assembly: 'they will gather together his elect from the four winds, from one end of the heavens to the other' (Matt 24:31). The kingship of YHWH that is declared over assembled Israel reaches its consummation in Christ's universal kingship: 'at the name of Jesus every knee should bow, in heaven and on earth and under the earth' (Phil 2:10) — the ultimate tribal assembly before the ultimate King.</p>",
    "6": "<p>'Let Reuben live and not die, though his numbers remain small' — the minimal blessing for Reuben, the firstborn who forfeited his birthright through sexual sin (Gen 49:3-4). The brevity of the blessing is itself expressive: Reuben survives but does not thrive. Paul's theology of grace uses the same logic in reverse for believers: they are not merely surviving by divine tolerance but 'more than conquerors through him who loved us' (Rom 8:37). The Reuben-blessing is the floor of grace — even the disgraced firstborn is preserved — but Christ offers the ceiling of grace that Reuben never received.</p>",
    "7": "<p>'Hear, O LORD, the voice of Judah, and bring him back to his people. His hands fight for him; be his help against his enemies' — Judah's blessing is a prayer for the tribe from whom the Messiah comes. The Lion of the tribe of Judah (Rev 5:5) is the ultimate fulfillment of the warrior-king who fights and conquers. The prayer 'bring him back to his people' anticipates the return of the Messianic King: Jesus the Judean who was rejected ('he came to that which was his own, but his own did not receive him,' John 1:11) will be received when they say 'blessed is he who comes in the name of the LORD' (Matt 23:39; quoting Ps 118:26).</p>",
    "8": "<p>'Grant your Thummim to Levi and your Urim to your faithful servant' — the Urim and Thummim, the priestly oracular instruments, are given to the Levitical priesthood. Hebrews' entire argument is that Christ supersedes the Levitical priesthood (Heb 7:11-14): 'if perfection could have been attained through the Levitical priesthood ... why was there still need for another priest to come, one in the order of Melchizedek?' The Urim and Thummim could only produce yes/no answers; Christ is the full revelation of God's will (Heb 1:1-2: 'in these last days he has spoken to us by his Son').</p>",
    "9": "<p>'He put loyalty to God above family ties, not acknowledging his father and mother, not favoring his brothers or his own children. They observed your word and guarded your covenant' — the Levitical devotion that subordinates natural family bonds to covenant obligation. Jesus applies the same principle more radically: 'anyone who loves their father or mother more than me is not worthy of me' (Matt 10:37); 'whoever does God's will is my brother and sister and mother' (Mark 3:35). The covenant community redefined by spiritual rather than natural kinship is the pattern Moses describes for Levi and that Jesus generalizes to all disciples.</p>",
    "10": "<p>'They will teach Jacob your decrees and Israel your law; they will offer incense before you and present burnt offerings on your altar' — the double Levitical vocation: teaching and sacrifice. Christ fulfills both perfectly: he is the great teacher (Matt 5-7; 23:8: 'you have one Teacher, the Messiah') and the great high priest whose one offering supersedes all Levitical sacrifice (Heb 10:14: 'by one sacrifice he has made perfect forever those who are being made holy'). Revelation 5:10 applies both vocations to the redeemed: 'you have made them to be a kingdom and priests to serve our God.'</p>",
    "11": "<p>'Bless his resources, LORD, and take pleasure in what he does. Shatter the strength of his enemies, those who hate him, so they cannot rise' — the prayer for Levitical effectiveness and the defeat of enemies. Christ's intercession for his servants follows the same two-part pattern: he prays for their success in mission ('I have given them your word and the world has hated them,' John 17:14) and for their protection ('protect them by the power of your name,' John 17:11). The enemies 'who cannot rise' anticipate Paul's declaration that 'the God of peace will soon crush Satan under your feet' (Rom 16:20).</p>",
    "12": "<p>'The beloved of the LORD rests in safety. The Most High shelters him all day long and dwells between his shoulders' — Benjamin's blessing as the most intimate divine protection in the chapter. Paul was from the tribe of Benjamin (Rom 11:1; Phil 3:5) — the apostle to the Gentiles came from the tribe described as dwelling in YHWH's shelter. The 'beloved' (<em>yĕdîd</em>) language connects to the divine declarations at Jesus's baptism and transfiguration: 'this is my Son, whom I love' (<em>ho agapētos</em>, Matt 3:17; 17:5). The Benjamin-blessed who 'rests in safety' is the prototype of 'I will never leave you nor forsake you' (Heb 13:5).</p>",
    "13": "<p>'May the LORD bless his land with the finest gifts of heaven above and of the deep waters beneath' — Joseph's agricultural blessing draws on the creation structure: heaven above, waters below (Gen 1:6-8). The double-hemisphere blessing (heaven and deep) for Joseph's land anticipates the new creation's comprehensive renewal: 'the creation waits in eager expectation for the children of God to be revealed' (Rom 8:19); the new heaven and new earth where 'the sea was no more' (Rev 21:1 — the primordial deep transformed). Joseph himself is a type of Christ: rejected by his brothers, enslaved, falsely accused, exalted to the right hand of Pharaoh, and used to save both Israel and the nations.</p>",
    "14": "<p>'With the best crops grown under the sun, and the finest harvests brought by each season' — the seasonal abundance of Joseph's land represents the fullness of created provision. Jesus's parables of harvest abundance (the sower, the wheat and tares, the tenants of the vineyard) draw on the same agricultural fullness as the theological medium of covenant fruitfulness. The 'finest harvests' of each season become, in John 15, the fruit that disciples bear when abiding in the vine — the agricultural covenant-blessing mediated through the true vine who is Christ himself.</p>",
    "15": "<p>'With the richest produce of the age-old mountains and the abundance of the everlasting hills' — the geological permanence of the mountains as the store of ancient blessing. Psalm 121:1-2: 'I lift up my eyes to the mountains — where does my help come from? My help comes from the LORD, the Maker of heaven and earth.' The everlasting hills as a figure of enduring divine provision anticipates the Rock that is higher than I (Ps 61:2) and the eternal foundation in Christ that no storm can shake (Matt 7:24-25).</p>",
    "16": "<p>'The goodwill of him who appeared in the burning bush' — the burning-bush theophany (Exod 3:2-6) is identified as the personal divine patron of Joseph's tribe. Jesus's 'before Abraham was, I am' (John 8:58) identifies himself as the 'I AM' of the burning bush — the same divine person who appeared to Moses and promised the land is the one who came in the flesh. The goodwill of the bush-deity resting on Joseph's tribe is the same divine goodwill that 'dwelt among us' (John 1:14: <em>eskenōsen</em>, tabernacled) in Jesus, the one in whom 'God was pleased to have all his fullness dwell' (Col 1:19).</p>",
    "17": "<p>'His firstborn bull has majesty — his horns are like the horns of a wild ox. With them he will drive the nations to the ends of the earth, they are the myriads of Ephraim and the thousands of Manasseh' — the ox-strength imagery for Joseph's tribal expansion. The 'driving the nations to the ends of the earth' anticipates Acts 1:8: 'you will be my witnesses in Jerusalem, and in all Judea and Samaria, and to the ends of the earth' — the apostolic mission that drives out not nations by force but the knowledge of sin and the proclamation of Christ to the uttermost parts. Revelation 7:4-8's 144,000 represent the full twelve tribes in the new covenant completion of Joseph's tribal expansion.</p>",
    "18": "<p>'Rejoice, Zebulun, in your ventures abroad, and Issachar, in your tents' — the complementary blessing of the active (Zebulun at sea) and the contemplative (Issachar in tents). Isaiah 9:1-2 (quoted in Matt 4:15-16) specifically names Zebulun and Naphtali as the region where 'the people living in darkness have seen a great light' — the very tribes that heard the least blessing of Moses's Song become the location of Jesus's primary Galilean ministry. The darkness of Zebulun and Naphtali was precisely where the great light was first displayed.</p>",
    "19": "<p>'They will summon nations to their mountain and offer sacrifices there that are right. They will draw from the abundance of the seas' — the mountain-sacrifice includes 'nations' being summoned — the universal worship that Isaiah 2:2-4 envisions: 'in the last days the mountain of the LORD's temple will be established as the highest of the mountains ... all nations will stream to it.' The 'right sacrifices' on the mountain anticipate the worship in spirit and truth that Jesus promised the Samaritan woman: 'a time is coming when you will worship the Father neither on this mountain nor in Jerusalem' (John 4:21-23) — the sacrifice of praise that supersedes geographical limitation.</p>",
    "20": "<p>'Blessed is he who gives Gad room to grow! He crouches like a lion, tearing arm and scalp' — Gad's lion-crouch anticipates the Lion of the tribe of Judah (Rev 5:5), though Gad's lion is a tribal warrior's image. The lion-tearing imagery used for God's defenders is the same imagery Revelation applies to Christ: 'the Lion of the tribe of Judah, the Root of David, has triumphed' (Rev 5:5). The roaming lion of Gad becomes, in Christ, the Lion who has already conquered — not by tearing the enemy but by being slain and rising again.</p>",
    "21": "<p>'He secured the best territory for himself, where a leader's portion was set aside. He marched with the heads of the people and carried out the LORD's righteous acts' — Gad as the tribe that established its own portion east of the Jordan while still honoring the covenant commitment to help the western tribes conquer their land. Paul's apostolic pattern follows a similar logic: he established himself in new territory but 'did not build on someone else's foundation' (Rom 15:20) and yet kept full solidarity with the Jerusalem church. Christ's own pattern: he secured the eternal inheritance through his death but remained in full covenant solidarity with his people throughout.</p>",
    "22": "<p>'Dan is a lion's cub that springs out of Bashan' — the leaping-lion image for Dan captures a tribe that acted decisively in conquest. Dan's geographical instability (they lost their original inheritance and migrated north to Bashan: Judg 18) is transformed by the blessing's image into dynamic power. The contrast between apparent weakness and actual power runs throughout the christological pattern: 'God chose the weak things of the world to shame the strong' (1 Cor 1:27). The lion cub that springs is the image of unexpected strength emerging from apparent vulnerability.</p>",
    "23": "<p>'Naphtali — overflowing with favor, full of the LORD's blessing — take possession of the sea and the south' — Naphtali, like Zebulun (v. 18), is the tribe of Galilee, the region where Jesus conducted most of his ministry. Matthew 4:13-16 quotes Isaiah 9:1-2 to identify Capernaum in Naphtali as the fulfillment of the prophecy: 'Galilee of the Gentiles — the people living in darkness have seen a great light.' The 'overflowing with favor, full of the LORD's blessing' that Moses pronounces over Naphtali is the blessing that landed most concretely in the Sea of Galilee region where Jesus called his first disciples and performed his first miracles.</p>",
    "24": "<p>'Most blessed among sons is Asher; may he be the favorite of his brothers and may he dip his feet in olive oil' — Asher's blessing of agricultural abundance (olive oil = Galilee/Asher territory's primary export). The prophetess Anna, who recognized the infant Jesus in the temple (Luke 2:36-38), was 'of the tribe of Asher' — the most blessed son's tribe produced the first person to publicly bear witness to Christ as the redemption of Jerusalem. The olive oil blessing of Asher becomes, in Anna, the anointing witness to the anointed one.</p>",
    "25": "<p>'Your bolts shall be iron and bronze; may your strength match the length of your days' — Asher's protective bolts and enduring strength. The promise of strength matching the length of days is the covenant-life formula: vitality proportional to lifespan. Paul applies the same principle to the spiritual life: 'our light and momentary troubles are achieving for us an eternal glory that far outweighs them all' (2 Cor 4:17) — the proportion is supernatural, with eternal weight exceeding temporal suffering. Christ's strength was fully maintained 'to the end' (John 13:1) — the days were matched by unfailing power.</p>",
    "26": "<p>'There is no one like the God of Jeshurun, who rides through the heavens to help you, through the skies in his majesty' — the divine warrior who rides through the heavens. Paul quotes Psalm 68:18 in Ephesians 4:8 ('when he ascended on high, he took many captives and gave gifts to his people') to describe the ascension of Christ. The one who 'rides through the heavens' in Deuteronomy 33 is the one who 'ascended higher than all the heavens, in order to fill the whole universe' (Eph 4:10). The divine majesty of the heavenly rider is the same majesty that emptied itself in the Incarnation and was restored at the ascension.</p>",
    "27": "<p>'The eternal God is your refuge, and underneath are his everlasting arms. He drives out the enemy before you and commands, Destroy them!' — one of the most beloved verses in Deuteronomy. The 'everlasting arms' (<em>zerōʿōt ʿôlām</em>) are the permanent divine support beneath the covenant community. Paul's climactic conclusion in Romans 8:38-39 — 'neither death nor life ... nor anything else in all creation, will be able to separate us from the love of God that is in Christ Jesus our Lord' — is the NT form of the everlasting arms: nothing can remove the community from the divine grip. Christ is the everlasting arms made flesh (John 1:14).</p>",
    "28": "<p>'Israel has lived in safety, Jacob alone in a land of grain and new wine, under a sky that drips with dew' — the covenant security of a people dwelling safely under divine protection, with agricultural abundance. This is the eschatological vision that the Prophets regularly invoke (Mic 4:4; Zech 3:10: 'each of you will invite your neighbor to sit under your vine and under your fig tree'). The new Jerusalem's river of the water of life and the tree of life yielding twelve crops (Rev 22:1-2) is the ultimate fulfillment of Jacob dwelling safely in a land of grain and wine.</p>",
    "29": "<p>'What happiness is yours, O Israel! Who is like you — a people saved by the LORD, the shield who helps you, the sword of your victory! Your enemies will cower before you, and you will tread on their high places' — Moses's final benediction is a beatitude: <em>ʾašrêkā yiśrāʾēl</em> (How blessed are you, O Israel). The Beatitudes of Jesus (Matt 5:3-12) are the same beatitude-form applied to the new covenant community: 'blessed are the poor in spirit, for theirs is the kingdom of heaven.' The YHWH who is 'the shield who helps you, the sword of your victory' is ultimately the Christ who 'gives us the victory through our Lord Jesus Christ' (1 Cor 15:57) over the last enemy, death itself.</p>",
  },
  "34": {
    "1": "<p>Moses climbs to the top of Mount Nebo — the final ascent of the covenant mediator who will not descend again. The mountain-ascent before a pivotal divine act is a recurring biblical pattern: Sinai (Exod 19), Carmel (1 Kings 18), the Mount of Transfiguration (Matt 17), Golgotha ('Calvary' = 'skull-place' = hill), and the Mount of Olives for the ascension (Acts 1:12). From Nebo, YHWH showed Moses the whole land — the same surveying function as the temptation mountain (Matt 4:8: 'the devil took him to a very high mountain and showed him all the kingdoms of the world') — except Moses sees the covenant inheritance, where Jesus sees and rejects the substitute.</p>",
    "2": "<p>The panoramic inventory of the land from Dan to the Negev, from the Mediterranean to the Jordan — the whole of what YHWH is giving to Israel. The land's comprehensiveness in Moses's vision is the type of the comprehensive inheritance Christ has secured: 'in my Father's house are many rooms' (John 14:2); 'I am making everything new' (Rev 21:5). The new creation that Paul describes as 'all things' being 'summed up' in Christ (Eph 1:10: <em>anakephalaiōsasthai</em>, to recapitulate all things in Christ) is the eschatological land-vision, infinitely expanded.</p>",
    "3": "<p>The Negeb and the Jordan Valley and Jericho — the last geographical items in the promised-land survey. Jericho is specifically named as 'the city of palms' — the same Jericho where Jesus healed blind Bartimaeus (Mark 10:46-52) and encountered Zacchaeus (Luke 19:1-10). The land that Moses could only survey becomes the territory of Jesus's ministry — the view from Nebo is partially realized in every healing and restoration Jesus performs in the Promised Land's geography.</p>",
    "4": "<p>'This is the land I promised to Abraham, Isaac, and Jacob, saying, I will give it to your descendants. I have let you see it with your own eyes, but you will not cross over into it' — the divine promise of Abraham (Gen 12:7; 15:18-21; 26:4; 28:13-15) is confirmed and simultaneously shown to Moses as the boundary of Moses's covenant role. Paul's Galatians argument crystallizes the distinction: the Abrahamic promise of the inheritance was given 430 years before the Mosaic law (Gal 3:17); Moses's covenant is the time-bound guardian, while Abraham's is the permanent promise — and Christ is the singular 'seed' who inherits all of Abraham's promise (Gal 3:16).</p>",
    "5": "<p>'So Moses the servant of the LORD died there in the land of Moab, just as the LORD had said' — Moses's death is attributed to a divine word: 'just as the LORD had said' connects every act of the servant's life to the divine speech that shaped it. Paul applies the same word-governed logic to Christ: 'Christ died for our sins according to the Scriptures, and he was buried, and he was raised on the third day according to the Scriptures' (1 Cor 15:3-4). The deaths of both Moses and Jesus were not accidents but the fulfillment of what YHWH had said. Moses's death closes the law; Christ's death fulfills it.</p>",
    "6": "<p>'The LORD buried him in a valley in Moab ... No one has ever found the location of his grave, to this day' — the divine burial of Moses with no locatable tomb. Jude 9 references a dispute between Michael the archangel and the devil over Moses's body — suggesting that the empty grave is theologically significant, not merely incidental. Christ's tomb, by contrast, is locatable (and verifiably empty); the empty tomb of Christ is not concealed but proclaimed as the foundational evidence of resurrection (1 Cor 15:4-8). Moses's hidden grave anticipates the transformative emptiness of Christ's known tomb.</p>",
    "7": "<p>'Moses was a hundred and twenty years old when he died, yet his eyesight was still sharp and his strength had not faded' — the undimmed vitality of Moses at death contrasts with the normal decline of human life under the curse (cf. the darkened eyes and weakened strength of Jacob, Gen 48:10). The undimmed eye and unabated strength point toward the resurrection body: 'the body that is sown is perishable, it is raised imperishable ... it is sown in weakness, it is raised in power' (1 Cor 15:42-43). Christ's resurrection body was 'imperishable' (1 Cor 15:52-54) — the ultimate undimmed-eye and unabated-strength, permanent and never fading again.</p>",
    "8": "<p>'The Israelites mourned for Moses in the plains of Moab for thirty days, until their weeping and mourning came to an end' — the thirty-day mourning period, the same as for Aaron (Num 20:29). Community grief has a divinely-bounded season: mourning is appropriate and honored with time, but it ends. Jesus wept at Lazarus's tomb (John 11:35) — validating communal grief — but also raised him, establishing the limit on mourning. Revelation 21:4: 'he will wipe every tear from their eyes. There will be no more death or mourning or crying or pain' — the final end of mourning, when the thirty days become eternal day.</p>",
    "9": "<p>'Joshua son of Nun was filled with the spirit of wisdom because Moses had laid his hands on him. So the Israelites listened to Joshua and did what the LORD had commanded Moses' — the laying on of hands transmits both the spirit and the authority. Jesus breathed on the disciples and said 'receive the Holy Spirit' (John 20:22); the Spirit given at Pentecost is the fulfillment of Moses's hand-laying pattern. The disciples 'listened to Joshua/Jesus' as the Israelites listened to their Joshua — both are the successors who complete what the law-giver began. Hebrews 4:8 explicitly identifies Joshua's rest as insufficient and points to the greater rest that Jesus brings.</p>",
    "10": "<p>'No prophet has arisen in Israel since who was like Moses — one whom the LORD knew face to face' — the limit-claim that Deuteronomy itself promised would be surpassed (Deut 18:15: 'the LORD your God will raise up for you a prophet like me from among you, from your fellow Israelites'). John 1:18 answers the face-to-face claim directly: 'no one has ever seen God, but the one and only Son, who is himself God and is at the Father's side, has made him known.' Moses knew YHWH face to face; Jesus is the face of God. The transfiguration (Matt 17:1-8) places Moses beside Jesus on the mountain and then replaces the Mosaic voice with the divine declaration: 'this is my Son, whom I love; with him I am well pleased. Listen to him!'</p>",
    "11": "<p>'No one else performed all the signs and wonders the LORD sent him to do in Egypt' — the signs and wonders of the Exodus define the standard of prophetic authentication. Peter's Pentecost sermon applies the same criterion to Jesus: 'Jesus of Nazareth was a man accredited by God to you by miracles, wonders and signs, which God did among you through him, as you yourselves know' (Acts 2:22). The author of Hebrews grounds the confirmation of the new covenant in an even higher witness: 'this salvation ... was confirmed to us by those who heard him. God also testified to it by signs, wonders and various miracles' (Heb 2:3-4). Jesus's signs exceed Moses's in scope and in the nature of what they reveal — life given, not only plagues inflicted.</p>",
    "12": "<p>'Or the mighty power and awesome deeds that Moses displayed before all Israel' — Deuteronomy closes with Moses as the high-water mark of prophetic ministry. But the book itself carries within it the promise of its own supersession (Deut 18:15-19) — the very document that honors Moses most points beyond him. John 20:30-31 closes with the same motif transposed: 'Jesus performed many other signs in the presence of his disciples, which are not recorded in this book. But these are written that you may believe that Jesus is the Messiah, the Son of God, and that by believing you may have life in his name.' Where Deuteronomy concludes with Moses's unrepeated deeds, John concludes with Christ's inexhaustible signs — and the life they offer that Moses's deeds never could.</p>",
  },
}

def main():
    existing = load_comm('mkt-christ', 'deuteronomy')
    merge_comm(existing, DEUT)
    save_comm('mkt-christ', 'deuteronomy', existing)
    il = json.loads((ROOT / 'data/interlinear/deuteronomy.json').read_text())
    out = json.loads((ROOT / 'data/commentary/mkt-christ/deuteronomy.json').read_text())
    all_ok = True
    for ch in range(32, 35):
        ck = str(ch)
        missing = [v for v in il.get(ck, {}) if v not in out.get(ck, {})]
        if missing:
            print(f'  ch {ch} MISSING: {missing}')
            all_ok = False
        else:
            print(f'  ch {ch}: OK ({len(il.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present ✓')

if __name__ == '__main__':
    main()
